snippet JavaScript aggiornato per l'ecosistema Albeni 1905. Ho integrato una logica di rilevamento automatico della lingua (tramite impostazioni del browser e struttura dell'URL) nel payload inviato all'AI Orchestration Layer.
Questa modifica è cruciale per alimentare correttamente l'AI Translation Layer e garantire che il calcolo dell'Intent Depth Score (IDS) e il routing siano localizzati per i mercati IT, EN, FR, DE ed ES.
Snippet AI Orchestration (Versione Multilingua)
JavaScript
(function() {
    // 1. Rilevamento Lingua (URL path o Browser)
    const getLanguageContext = () => {
        const pathSegments = window.location.pathname.split('/');
        const supportedLangs = ['it', 'en', 'fr', 'de', 'es'];
        // Controlla se la lingua è nel primo segmento dell'URL (es. /de/...)
        const urlLang = supportedLangs.find(lang => pathSegments.includes(lang));
        return urlLang || (navigator.language || navigator.userLanguage).split('-')[0];
    };
    const currentLang = getLanguageContext();
    // 2. Configurazione Identità Cross-Dominio
    const urlParams = new URLSearchParams(window.location.search);
    let userId = urlParams.get('uid') || localStorage.getItem('albeni_uid');
    if (!userId) {
        userId = 'id_' + Math.random().toString(36).substr(2, 9);
    }
    localStorage.setItem('albeni_uid', userId);
    // 3. Dispatcher API con Parametro Lingua
    const sendSignal = (eventType, metadata = {}) => {
        fetch('https://api.albeni1905.com/v1/track/event', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                user_id: userId,
                domain: window.location.hostname,
                lang: currentLang, // <--- Parametro Lingua Integrato
                event_type: eventType,
                metadata: metadata,
                timestamp: Date.now()
            })
        }).catch(err => console.error('AI Signal Error:', err));
    };
    // 4. Sensore Dwell Time (>60s)
    let dwellTriggered = false;
    setTimeout(() => {
        if (!dwellTriggered) {
            sendSignal('dwell_time_reached', { seconds: 60 });
            dwellTriggered = true;
        }
    }, 60000);
    // 5. Sensore Scroll Depth (25/50/75/90%)
    const scrollMilestones = [25, 50, 75, 90];
    const triggeredMilestones = new Set();
    window.addEventListener('scroll', () => {
        const scrollPercent = Math.round((window.scrollY + window.innerHeight) / document.documentElement.scrollHeight * 100);
        scrollMilestones.forEach(m => {
            if (scrollPercent >= m && !triggeredMilestones.has(m)) {
                triggeredMilestones.add(m);
                sendSignal('scroll_depth', { depth: m });
            }
        });
    });
    // 6. Sensore Interazioni Tecniche
    document.addEventListener('click', (e) => {
        const target = e.target;
        if (target.matches('.btn-compare, .video-material, .download-lead-magnet')) {
            sendSignal('technical_interaction', { 
                element: target.className,
                text: target.innerText,
                context_lang: currentLang
            });
        }
    });
    // 7. Hook di Routing Dinamico (MOFU/BOFU check) localizzato
    window.checkAIRouting = async function() {
        const response = await fetch(`https://api.albeni1905.com/v1/router/assign?user_id=${userId}&lang=${currentLang}`);
        const data = await response.json();
        if (data.redirect_to && data.redirect_to !== window.location.origin) {
            // Assicura la persistenza dell'ID e della lingua nel redirect
            window.location.href = `${data.redirect_to}?uid=${userId}&lang=${currentLang}`;
        }
    };
})();
Miglioramenti Strategici Introdotti
Coerenza MTPE: Il rilevamento della lingua permette di verificare se il modello Machine Translation + Post Editing sta mantenendo la coerenza narrativa e i glossari tecnici nei mercati esteri.
Precisione per il Mercato Tedesco: Consente all'AI di applicare correttamente il registro "Sachlich-elegant" (formale con il "Sie") per gli utenti identificati in area DE.
Segmentazione Dashboard: L'AI Analyst può ora filtrare i KPI (CPA, CR, IDS) per lingua, permettendo alla governance di monitorare la soglia di allerta CPA (<15€) specificamente per mercati ad alto costo come Francia o Germania .
Routing Multi-Dominio Localizzato: Evita l'errore critico di indirizzare un utente che naviga in inglese su contenuti TOFU verso una pagina di checkout BOFU in italiano.
Nota per lo Sviluppo
Assicurati che i tuoi siti WordPress e Shopify utilizzino sottocartelle standard per le lingue (es. /de/, /fr/) per massimizzare l'efficacia della funzione getLanguageContext.

