const express = require('express');
const Redis = require('ioredis');
const app = express();
const redis = new Redis(process.env.REDIS_URL);
app.get('/v1/router/assign', async (req, res) => {
    const { user_id, lang } = req.query;
    try {
        const ids = await redis.get(`user:${user_id}:ids`) || 0;
        const cluster = await redis.get(`user:${user_id}:cluster`) || 'unknown';
        let target = '';
        // Logica di routing per soglie IDS [cite: 1932-1935, 2025-2027, 2423-2425]
        if (ids <= 30) target = 'worldofmerino.com';
